import java.io.InputStream;
import java.security.KeyStore;
import java.security.cert.CertificateFactory;
import java.security.cert.X509Certificate;
import java.util.Arrays;
import java.util.List;

public class SecureHttpClient {

    private static final String TRUST_STORE_PATH = "path/to/truststore";
    private static final String TRUST_STORE_PASSWORD = "truststore_password";

    public InputStream getSecureDataFromServer(String url) throws Exception {
        HttpsURLConnection connection = (HttpsURLConnection) new URL(url).openConnection();
        KeyStore trustStore = KeyStore.getInstance(KeyStore.getDefaultType());
        trustStore.load(null, null);

        CertificateFactory cf = CertificateFactory.getInstance("X.509");
        List<X509Certificate> certificates = Arrays.asList(
                (X509Certificate) cf.generateCertificate(new FileInputStream(TRUST_STORE_PATH))
        );

        trustStore.setCertificates(certificates.toArray(new X509Certificate[0]), null);

        SSLContext sslContext = SSLContext.getInstance("TLS");
        sslContext.init(null, new TrustManager[]{new X509TrustManager() {
            @Override
            public void checkClientTrusted(X509Certificate[] chain, String authType) {}

            @Override
            public void checkServerTrusted(X509Certificate[] chain, String authType) {}

            @Override
            public X509Certificate[] getAcceptedIssuers() {
                return new X509Certificate[0];
            }
        }}, new SecureRandom());

        connection.setSSLSocketFactory(sslContext.getSocketFactory());
        connection.connect();

        return connection.getInputStream();
    }
}
